class TestZipDicts:
    """Tests for zip_dicts function."""

    # ==================== HAPPY PATH ====================
    @pytest.mark.parametrize("input_dicts, expected", [
        # Overlapping keys with missing keys in some dicts
        (
            ({"a": 1, "b": 2}, {"a": 3, "c": 4}),
            {"a": [1, 3], "b": [2, None], "c": [None, 4]}
        ),
        # Identical keys across multiple dicts
        (
            ({"x": 1}, {"x": 2}, {"x": 3}),
            {"x": [1, 2, 3]}
        ),
        # Completely disjoint keys
        (
            ({"a": 1}, {"b": 2}),
            {"a": [1, None], "b": [None, 2]}
        ),
        # Mixed value types (strings, lists, ints)
        (
            ({"k1": "str", "k2": [1, 2]}, {"k1": 42, "k2": None}),
            {"k1": ["str", 42], "k2": [[1, 2], None]}
        ),
        # Explicit None values vs missing keys (both yield None)
        (
            ({"a": None}, {"a": 1}),
            {"a": [None, 1]}
        ),
    ])
    def test_happy_path(self, input_dicts, expected):
        """Standard usage with various key/value combinations."""
        result = zip_dicts(*input_dicts)
        assert result == expected

    # ==================== EDGE CASES ====================
    def test_no_arguments(self):
        """Calling with zero arguments should return an empty dict."""
        assert zip_dicts() == {}

    def test_single_dictionary(self):
        """Single dict should wrap each value in a list."""
        assert zip_dicts({"a": 1, "b": 2}) == {"a": [1], "b": [2]}

    def test_all_empty_dictionaries(self):
        """Multiple empty dicts should return an empty dict."""
        assert zip_dicts({}, {}, {}) == {}

    def test_mixed_empty_and_non_empty(self):
        """Empty dicts should contribute None to the value lists."""
        assert zip_dicts({}, {"a": 1}, {}) == {"a": [None, 1, None]}

    def test_preserves_input_order_in_value_lists(self):
        """Values in the output lists must match the order of input dicts."""
        d1 = {"key": "first"}
        d2 = {"key": "second"}
        d3 = {"key": "third"}
        result = zip_dicts(d1, d2, d3)
        assert result["key"] == ["first", "second", "third"]

    # ==================== ERROR CASES ====================
    def test_non_iterable_raises_type_error(self):
        """Passing a non-iterable (e.g., int) should raise TypeError."""
        with pytest.raises(TypeError, match="'int' object is not iterable"):
            zip_dicts(42)

    def test_none_argument_raises_type_error(self):
        """Passing None should raise TypeError."""
        with pytest.raises(TypeError, match="'NoneType' object is not iterable"):
            zip_dicts(None)

    def test_non_dict_iterable_raises_attribute_error(self):
        """Passing an iterable without .get() (e.g., list) should raise AttributeError."""
        with pytest.raises(AttributeError, match="'list' object has no attribute 'get'"):
            zip_dicts([1, 2, 3])

    def test_mixed_valid_and_invalid_raises_error(self):
        """Mixing valid dicts with invalid types should fail fast."""
        with pytest.raises((TypeError, AttributeError)):
            zip_dicts({"a": 1}, "not a dict")
